import type { SeriesActionsTemplate } from '../../core/types/series-actions-template.js';
import type { HistogramChartProps } from '../../histogram/types/histogram-props.js';
import type {
  HistogramBin,
  HistogramSeries,
} from '../../histogram/types/histogram.js';
import type {
  XYChartBarSeries,
  XYChartBarSeriesActionItem,
} from '../../xy-chart/types/xy-chart.js';

/**
 * Maps the Histogram `seriesActions` callback to the XYChart BarSeries `actions` callback.
 *
 * Translates XYChart bar datapoint and series information back into
 * HistogramSeries and HistogramBin types before invoking the original callback.
 */
export function mapHistogramSeriesActionsToXY(
  seriesActions: NonNullable<HistogramChartProps['seriesActions']>,
  originalData: HistogramSeries[],
): (
  datapoint: XYChartBarSeriesActionItem,
  series?: XYChartBarSeries,
) => SeriesActionsTemplate {
  return (
    datapoint: XYChartBarSeriesActionItem,
    _series?: XYChartBarSeries,
  ): SeriesActionsTemplate => {
    const bin: HistogramBin = {
      from: datapoint.datapoint.x0 as number,
      to: datapoint.datapoint.x1 as number,
      value: datapoint.datapoint.y1 as number,
    };

    const histogramSeries = originalData.find(
      (s) => s.name === datapoint.name,
    ) ?? {
      name: datapoint.name,
      bins: [bin],
    };

    return seriesActions(histogramSeries, bin);
  };
}
